import{_ as s,o as i,c as t,a3 as n}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"Onboarding & Fonctionnement","description":"","frontmatter":{"title":"Onboarding & Fonctionnement"},"headers":[],"relativePath":"publishers/onboarding-process.md","filePath":"publishers/onboarding-process.md"}'),a={name:"publishers/onboarding-process.md"};function o(r,e,l,d,u,c){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="onboarding-et-fonctionnement" tabindex="-1">Onboarding et Fonctionnement <a class="header-anchor" href="#onboarding-et-fonctionnement" aria-label="Permalink to &quot;Onboarding et Fonctionnement&quot;">​</a></h1><p>Bienvenue sur getinside ! Ne vous contentez pas d&#39;attendre les campagnes : prenez le contrôle de votre régie, activez vos partenaires historiques et maximisez vos revenus.</p><h2 id="phase-1-configuration-et-activation" tabindex="-1">Phase 1 : Configuration et Activation <a class="header-anchor" href="#phase-1-configuration-et-activation" aria-label="Permalink to &quot;Phase 1 : Configuration et Activation&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Démo &amp; Création du compte</h3><p>Tout commence par un call de démo avec l&#39;équipe getinside.</p><ul><li>L&#39;équipe crée votre compte e-commerçant.</li><li>Tous les contacts fournis reçoivent un email d&#39;invitation.</li><li><strong>Action :</strong> Cliquez sur le lien dans l&#39;email pour créer votre mot de passe et accéder à la plateforme.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Configuration Logistique</h3><p>Avant de créer vos audiences, définissez vos contraintes logistiques (indispensable pour l&#39;algorithme).</p><ul><li><strong>📍 Adresse de l&#39;entrepôt</strong> — Lieu de livraison des supports physiques (flyers, échantillons).</li><li><strong>⏱️ Lead Time (Délai d&#39;ingestion)</strong> — Délai incompressible entre la réception des palettes et le début de l&#39;insertion. Pris en compte automatiquement par l&#39;algorithme pour synchroniser les livraisons.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Création des Audiences</h3><p>Dans l&#39;onglet <strong>Monétisation</strong>, créez vos fiches audience : panier moyen, typologie B2B/B2C, profil du persona, visuels (logo, bannière). Une fiche complète améliore votre <strong>Score Distributeur</strong> (sur 5 étoiles) et votre visibilité sur la marketplace.</p><a href="audience-setup" class="btn btn-outline">Guide détaillé — Fiche Audience &amp; Score →</a></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Ajout des Types de Campagnes</h3><p>Pour chaque audience créée, ajoutez les types de campagnes acceptés et leurs critères :</p><ul><li><strong>📦 Insertion Colis :</strong> Capacité (max flyers simultanés), formats acceptés, volumes prévisionnels par semaine sur 12 mois.</li><li><strong>📧 Digital :</strong> CPM indicatif, exemples de campagnes passées, infos de performance (Taux d&#39;ouverture, Clics).</li></ul></div></div><div class="gi-step"><div class="gi-step-num">5</div><div class="gi-step-body"><h3>Validation (Call de contrôle)</h3><p>Dès que vous estimez avoir complété les infos, avertissez l&#39;équipe getinside.</p><ul><li>Nous proposons un call pour confirmer que toutes les infos nécessaires sont remplies.</li><li>Rappel des aspects techniques et des bonnes pratiques.</li></ul></div></div><div class="gi-step"><div class="gi-step-num done">✓</div><div class="gi-step-body"><h3>Activation</h3><p>Suite au call :</p><ul><li>✅ Les audiences et types de campagnes validés sont <strong>activés</strong>.</li><li>⏸️ Ceux qui sont incomplets restent non-référencés en attendant.</li></ul></div></div><h2 id="phase-2-gestion-des-campagnes" tabindex="-1">Phase 2 : Gestion des Campagnes <a class="header-anchor" href="#phase-2-gestion-des-campagnes" aria-label="Permalink to &quot;Phase 2 : Gestion des Campagnes&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">7</div><div class="gi-step-body"><h3>Visibilité Marketplace</h3><p>Une fois activées, les annonceurs peuvent voir vos audiences sur la plateforme et commencer à vous proposer des campagnes.</p></div></div><div class="gi-step"><div class="gi-step-num">8</div><div class="gi-step-body"><h3>Réception &amp; Négociation</h3><p>Lorsqu&#39;une campagne est proposée, tous vos utilisateurs reçoivent une notification.</p><p><strong>⏱️ Règle des 48 heures (Critique)</strong> — Répondez à toute proposition dans les <strong>48 heures ouvrées</strong>. Le silence vaut refus tacite et entraîne une pénalité égale à la commission perdue.</p><p><strong>Ne refusez pas, négociez !</strong> L&#39;objectif est de remplir votre inventaire :</p><ul><li><strong>💰 Prix trop bas ?</strong> Faites une contre-proposition tarifaire.</li><li><strong>📅 Dates indisponibles ?</strong> Proposez une autre période de diffusion.</li><li><strong>📦 Volume inadapté ?</strong> Ajustez la quantité proposée.</li></ul><p><strong>💬 Messagerie Intégrée :</strong> Utilisez le chat pour discuter avec l&#39;annonceur, argumenter votre prix ou demander des précisions.</p></div></div><div class="gi-step"><div class="gi-step-num done">9</div><div class="gi-step-body"><h3>Validation Opérationnelle</h3><p>Une fois la campagne validée par les deux parties, on avance sur l&#39;opérationnel :</p><ul><li><strong>Insertion Colis :</strong> Expédition des supports (respect du délai d&#39;ingestion).</li><li><strong>Digital :</strong> Transmission des assets créatifs et intégration.</li></ul></div></div><h2 id="phase-3-acceleration-autonomie" tabindex="-1">Phase 3 : Accélération &amp; Autonomie <a class="header-anchor" href="#phase-3-acceleration-autonomie" aria-label="Permalink to &quot;Phase 3 : Accélération &amp; Autonomie&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">🚀</div><div class="gi-step-body"><h3>Trade Marketing (Vos Marques)</h3><p>Ne dépendez pas uniquement des annonceurs externes. Soyez proactif avec vos propres fournisseurs !</p><div class="gi-accent-box"><strong>Le concept :</strong> Invitez les marques que vous distribuez à acheter de la visibilité chez vous (Insertion Colis, Email, Social) via getinside. <ul><li>✅ <strong>Simplification :</strong> Centralisez toute la gestion et la facturation au même endroit.</li><li>✅ <strong>Rentabilité :</strong> Générez des revenus additionnels sur des partenaires déjà acquis — <strong>0% de frais de régie</strong> avec les offres Plateforme ou Managed.</li></ul></div></div></div><div class="gi-step"><div class="gi-step-num">🤝</div><div class="gi-step-body"><h3>Affiliation &amp; Parrainage</h3><p>Vous connaissez d&#39;autres marques ou e-commerçants ?</p><ul><li>Invitez-les à rejoindre la plateforme.</li><li>Touchez une commission sur leur activité.</li><li><a href="affiliation">Voir le programme d&#39;affiliation</a>.</li></ul></div></div><h2 id="conditions-contractuelles-penalites" tabindex="-1">Conditions Contractuelles &amp; Pénalités <a class="header-anchor" href="#conditions-contractuelles-penalites" aria-label="Permalink to &quot;Conditions Contractuelles &amp; Pénalités&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Règles de Conformité Opérationnelle</p><p>Afin de maintenir un service de qualité pour tous nos partenaires, les conditions suivantes s&#39;appliquent.</p></div><h3 id="delai-de-reponse-regle-des-48-heures" tabindex="-1">Délai de Réponse (Règle des 48 heures) <a class="header-anchor" href="#delai-de-reponse-regle-des-48-heures" aria-label="Permalink to &quot;Délai de Réponse (Règle des 48 heures)&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Règle stricte : 48 heures ouvrées</p><p>Vous devez répondre à <strong>toute proposition de campagne en moins de 48 heures ouvrées</strong>.</p><p>Passé ce délai, l&#39;absence de réponse = refus tacite et entraîne une <strong>pénalité équivalente à la commission</strong> que nous aurions perçue sur la campagne.</p></div><h3 id="penalites-contractuelles" tabindex="-1">Pénalités Contractuelles <a class="header-anchor" href="#penalites-contractuelles" aria-label="Permalink to &quot;Pénalités Contractuelles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Situation</th><th>Montant</th><th>Détail</th></tr></thead><tbody><tr><td>Annulation après Validation</td><td><strong>550€ HT</strong></td><td>Forfait + perte de commission</td></tr><tr><td>Rupture Anticipée de Contrat</td><td><strong>1 550€ HT</strong></td><td>Indemnité pour engagement annuel non tenu</td></tr><tr><td>Contournement de Plateforme</td><td><strong>2 500€ HT / campagne</strong></td><td>Contact direct Annonceur ↔ Distributeur hors plateforme</td></tr></tbody></table><h3 id="protection-des-donnees-rgpd-first-party-data" tabindex="-1">Protection des Données (RGPD &amp; First Party Data) <a class="header-anchor" href="#protection-des-donnees-rgpd-first-party-data" aria-label="Permalink to &quot;Protection des Données (RGPD &amp; First Party Data)&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>🛡️ Les données sont exclusivement vôtres</strong></p><p>getinside agit comme un <strong>Tiers de Confiance</strong>. Aucun transfert de fichier client vers un Annonceur n&#39;est autorisé sans un nouvel Opt-in RGPD spécifique.</p><ul><li>Vous conservez la propriété de vos données client.</li><li>Les annonceurs ne reçoivent que les leads opt-in (jeux concours uniquement).</li><li>Toute demande de données supplémentaires requiert une validation légale.</li></ul></div><h3 id="droit-de-veto-distributeur" tabindex="-1">Droit de Veto Distributeur <a class="header-anchor" href="#droit-de-veto-distributeur" aria-label="Permalink to &quot;Droit de Veto Distributeur&quot;">​</a></h3><div class="gi-value-grid"><div class="gi-value-card"><strong>✅ Vous Pouvez Refuser</strong><ul><li><strong>La MARQUE :</strong> Raisons éthiques ou de concurrence.</li><li><strong>Légalité :</strong> Si le contenu porte atteinte aux lois.</li><li><strong>Image Marque :</strong> Si la campagne contredit vos valeurs.</li></ul></div><div class="gi-value-card"><strong>❌ Vous Ne Pouvez Pas Refuser</strong><ul><li><strong>Direction artistique :</strong> Si le visuel respecte les spécifications techniques.</li><li><strong>Préférences subjectives :</strong> &quot;Je ne trouve pas ça beau&quot; n&#39;est pas un motif valide.</li><li><strong>Raisons commerciales seules :</strong> Prix trop bas → Négociez plutôt que refuser.</li></ul></div></div>',26)])])}const v=s(a,[["render",o]]);export{g as __pageData,v as default};
